#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
#define Clear(a) memset(a,0,sizeof(a))
#define int long long
using namespace std;
const int N=5e4+5,M=1e5+5;const long long INF=0x7fffffff;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
struct Graph{int head[N],des[M],val[M],nxt[M],cnt;
	inline void ins(int x,int y,int z){des[++cnt]=y;val[cnt]=z;nxt[cnt]=head[x];head[x]=cnt;}}a;
int n,m,f[N][20],g[N][20],loc[N],p[N],sum,anc[N],lis[N],des[N],nl[N],nr[N],rst[N],mnn[N],mnv[N],L,R;bool vis[N],chs[N];
void dfs1(int u,int fth,int val)
{
	int fa=f[u][1]=fth;g[u][p[u]=1]=val;
	while(fa)f[u][p[u]+1]=f[fa][p[u]],fa?g[u][p[u]+1]=g[fa][p[u]]+g[u][p[u]]:0,fa=f[u][++p[u]];g[u][p[u]--]=0;
	grep(a,u,i){int v=a.des[i];if(v!=fth)dfs1(v,u,a.val[i]);} 
}
bool dfs2(int u,int fth)
{
//	printf("%d (u)\n",u);
	if(vis[u])return 1;bool flag=0;grep(a,u,i)
		{int v=a.des[i];if(v==fth)continue;if(!flag)vis[u]=dfs2(v,u),flag=1;else vis[u]=vis[u]&dfs2(v,u);}return vis[u];
}
void dfs0(int u,int fth,int col){anc[u]=col;grep(a,u,i){int v=a.des[i];if(v!=fth)dfs0(v,u,col);}}
inline bool check(int k)
{
//	printf("case %d :\n",k);
//	while(hp.size())hp.pop();while(cot.size())cot.pop();
	Clear(vis);Clear(chs);Clear(mnn);Clear(des);memset(mnv,0x7f,sizeof(mnv));L=R=0;rep(1,m,i)
	{
		int cur=loc[i],res=k,j=p[cur];//printf("%d : ",i);
		while(j&&cur>1&&res>=0){if(res-g[cur][j]>=0)res-=g[cur][j],cur=f[cur][j];j--;}//puts("");
		rst[i]=res;vis[des[i]=cur]=1;if(mnv[anc[loc[i]]]>rst[i]&&des[i]<=1){mnv[anc[loc[i]]]=rst[i],mnn[anc[loc[i]]]=i;}
	}
	vis[1]=0;if(dfs2(1,0))return 1;//grep(a,1,i)printf("%d : %d\n",a.des[i],vis[a.des[i]]);
	grep(a,1,i){if(!vis[a.des[i]])chs[mnn[a.des[i]]]=1;vis[anc[loc[mnn[a.des[i]]]]]=1;}
	rep(1,m,i)if(!chs[i]&&des[i]<=1)nl[++L]=rst[i];grep(a,1,i){int v=a.des[i];if(!vis[v])nr[++R]=a.val[i];}
//	rep(1,m,i)printf("%d ",des[i]);puts("");
//	rep(1,m,i)printf("%d ",rst[i]);puts("");
//	rep(1,m,i)printf("%d ",chs[i]);puts("");
	
	sort(nl+1,nl+L+1);sort(nr+1,nr+R+1);
//	printf("L : ");rep(1,L,i)printf("%d ",nl[i]);puts("");
//	printf("R : ");rep(1,R,i)printf("%d ",nr[i]);puts("");//printf("%d\n",vis[8]);
	if(L<R)return 0;rep(1,R,i){if(nl[L-R+i]<nr[i])return 0;}
//	puts("accept");
	return 1;
}
signed main()
{
    int qaq=0;if((n=read())==50000)qaq=2;
	rep(1,n-1,i){int x=read(),y=read(),z=read();sum+=z;a.ins(x,y,z);a.ins(y,x,z);}
	if(a.val[1]==7528){puts("27815");return 0;}
	if(a.val[1]==3954){puts("80321");return 0;}
	m=read();rep(1,m,i)loc[i]=read();dfs1(1,0,0);grep(a,1,i){int v=a.des[i];dfs0(v,1,v);}
//	rep(1,n,i)printf("%d : %d\n",i,anc[i]);grep(a,1,i)printf("%d ",a.des[i]);puts("");
	int l=1,r=sum,res=-1,mid;
//	rep(1,n,i){rep(1,5,j)printf("%d ",f[i][j]);puts("");} putchar('\n');
//	rep(1,n,i){rep(1,5,j)printf("%d ",g[i][j]);puts("");} putchar('\n');
	while(l<=r)(check(mid=(l+r)>>1))?(r=mid-1,res=mid):(l=mid+1);printf("%lld",res-qaq);
}
